class Solution {
public:
    string gcdOfStrings(string str1, string str2) {
        if (str1.length() == str2.length() ) {
            return "";
        }
        int temp = 0;
        string word;
        int mult = str1.length() / str2.length();
        for(int i = 0; i <= mult; i++){
            temp = 0;
            for (int x = 0; x < str2.length(); x++){
                if(str1[i+x] == str2[x]) 
                    temp += 1;
            }
            if (temp != str2.length()){
                for(int c = i + str2.length()-1; c != str1.length(); c++)
                    word += str1[c];
                return word;
            }
        }
        return word;
    }
};

